import React from "react";

const Hero = () => {
  const scrollTo = (id) => {
    document.getElementById(id)?.scrollIntoView({ behavior: "smooth" });
  };

  return (
    <>
      <style>{`
        .hero {
          position: relative;
          min-height: 100vh;
          display: flex;
          align-items: center;
          justify-content: center;
          overflow: hidden;
        }

        .hero__bg {
          position: absolute;
          inset: 0;
          background-image: url('https://images.unsplash.com/photo-1520250497591-112f2f40a3f4?w=1800&q=85&auto=format');
          background-size: cover;
          background-position: center 30%;
          transform: scale(1.05);
          animation: heroZoom 12s ease-in-out infinite alternate;
        }

        @keyframes heroZoom {
          from { transform: scale(1.05); }
          to   { transform: scale(1); }
        }

        .hero__overlay {
          position: absolute;
          inset: 0;
          background: linear-gradient(
            160deg,
            rgba(26, 58, 58, 0.75),
            rgba(0,0,0,0.6)
          );
        }

        .hero__content {
          position: relative;
          z-index: 2;
          text-align: center;
          padding: 20px;
          color: white;
        }

        .hero__eyebrow {
          font-size: 12px;
          letter-spacing: 3px;
          color: gold;
          margin-bottom: 20px;
        }

        .hero__title {
          font-size: clamp(2.5rem, 7vw, 5rem);
          margin-bottom: 20px;
        }

        .hero__title em {
          color: gold;
          font-style: italic;
        }

        .hero__desc {
          max-width: 500px;
          margin: 0 auto 30px;
          opacity: 0.8;
        }

        .hero__actions {
          display: flex;
          gap: 15px;
          justify-content: center;
          flex-wrap: wrap;
        }

        .btn-primary {
          padding: 10px 20px;
          background: gold;
          border: none;
          cursor: pointer;
        }

        .btn-outline {
          padding: 10px 20px;
          border: 1px solid white;
          background: transparent;
          color: white;
          cursor: pointer;
        }

        .hero__scroll {
          position: absolute;
          bottom: 100px;
          left: 50%;
          transform: translateX(-50%);
          cursor: pointer;
          text-align: center;
        }

        .hero__scroll-line {
          width: 2px;
          height: 40px;
          background: gold;
          margin: auto;
          animation: scrollPulse 2s infinite;
        }

        @keyframes scrollPulse {
          0% { opacity: 0.3; }
          50% { opacity: 1; }
          100% { opacity: 0.3; }
        }

        .hero__stats {
          position: absolute;
          bottom: 0;
          width: 100%;
          display: flex;
          background: rgba(0,0,0,0.7);
        }

        .hero__stat {
          flex: 1;
          text-align: center;
          padding: 15px;
          color: white;
        }

        .hero__stat-value {
          color: gold;
          font-size: 20px;
        }

        .hero__stat-label {
          font-size: 12px;
          opacity: 0.6;
        }

        @media (max-width: 600px) {
          .hero__stats {
            flex-wrap: wrap;
          }
          .hero__stat {
            width: 50%;
          }
        }
      `}</style>

      <section id="home" className="hero">
        <div className="hero__bg" />
        <div className="hero__overlay" />

        <div className="hero__content">
          <span className="hero__eyebrow">✦ Est. 2008 · Maldives ✦</span>

          <h1 className="hero__title">
            Where Luxury <br />
            <em>Meets the Sea</em>
          </h1>

          <p className="hero__desc">
            Experience serenity and luxury like never before.
          </p>

          <div className="hero__actions">
            <button className="btn-primary" onClick={() => scrollTo("rooms")}>
              Explore Rooms
            </button>
            <button className="btn-outline" onClick={() => scrollTo("contact")}>
              Book a Stay
            </button>
          </div>
        </div>

        <div className="hero__scroll" onClick={() => scrollTo("about")}>
          <div className="hero__scroll-line" />
          <span>Scroll</span>
        </div>

        <div className="hero__stats">
          {[
            { value: "48", label: "Rooms" },
            { value: "4.9★", label: "Rating" },
            { value: "15+", label: "Years" },
            { value: "∞", label: "Memories" },
          ].map((stat, i) => (
            <div key={i} className="hero__stat">
              <div className="hero__stat-value">{stat.value}</div>
              <div className="hero__stat-label">{stat.label}</div>
            </div>
          ))}
        </div>
      </section>
    </>
  );
};

export default Hero;
